    onContMainResize: function(element, info, eOpts) {
        console.log('>>>resizswse');
        console.log(element);

        console.log('>>>info');
        console.log(info);


        let width = info;

        // 1. Log para depurar
            console.log('El ancho actual es:', width);

            // 2. Lógica condicional
            // Importante: Verifica el layout actual para no forzarlo mil veces si no ha cambiado
            var currentLayout = this.getLayout().type;

            if (width < 1000 /*&& currentLayout !== 'vbox'*/) {
                console.log('-> Cambiando a Modo Móvil');
                this.setLayout('hbox');
            }
            else if (width >= 1000 /*&& currentLayout !== 'hbox'*/) {
                console.log('-> Cambiando a Modo Escritorio');
                this.setLayout('vbox');
            }

    },

    onBtnCreateTap: function(button, e, eOpts) {
        /*
        // Buscas el contenedor padre
        var contUser    = Ext.getCmp('contUser'); // Asegúrate de tener reference='contResource'
        var toolbarMain = Ext.getCmp('toolbarMain');

        // Cambias a la vista del formulario (que es el item 1)
        // La animación 'slide' hará que parezca que entras a una nueva página
        contUser.setActiveItem(1);
        toolbarMain.hide();
        */
        var form = Ext.getCmp("formConfig");
        form.isCreate = true;

        this.showForm();
    },

    onBtnLoadTap: function(button, e, eOpts) {
        Ext.getStore('storeUser').load();
    },

    onDataViewConfigChildtap: function(dataview, location, eOpts) {
        // 1. Detectar si el toque fue en un botón de acción
        // Buscamos la clase '.action-btn' en el elemento tocado o sus padres
        var btn = location.event.getTarget('.action-btn');

        if (btn) {
            // 2. Extraer la acción y el registro
            var action = btn.getAttribute('data-action');
            var record = location.record.data;

            // Detenemos la propagación para que no seleccione la fila al tocar el botón
            location.event.stopEvent();

            // 3. Switch Maestro de Acciones
            switch (action) {
                case 'view':
                    console.warn('Tap: view');
                    var form = Ext.getCmp("formConfig");
                    form.isCreate = false;
                    form.configRecord = record;
                    this.showForm();
                    break;

                case 'edit':
                    console.warn('Tap: view');
                    var form = Ext.getCmp("formConfig");
                    form.isCreate = false;
                    form.configRecord = record;
                    this.showForm();
                    break;

                case 'download':
                    console.warn('Tap: download');
                    this.downloadFile(record);
                    break;

                case 'email':
                    console.warn('Tap: email');
                    this.sendByEmail(record);
                    break;

                case 'whatsapp':
                    console.warn('Tap: whatsapp');
                    this.sendToWhatsApp(record);
                    break;

                case 'attach':
                    console.warn('Tap: attach');
                    this.copyLinkToClipboard(record);
                    break;

                case 'delete':
                    Ext.Msg.show({
                        title: 'Eliminar Registro',
                        message: '¿Realmente deseas eliminar este registro? Esta acción no se puede deshacer.',
                        width: 300, // Opcional
                        closable: false,
                        icon: Ext.Msg.QUESTION,
                        buttons: [
                            {
                                text: 'No',
                                itemId: 'no'
                            },
                            {
                                text: 'Sí, borrar',
                                itemId: 'yes',
                                ui: 'action-decline' // En Modern, esto suele poner el botón en rojo
                            }
                        ],
                        fn: function (buttonId) {
                            if (buttonId === 'yes') {

                                var idConfig = record.id_configuration;
                                appLocal.deleteConfig(idConfig);

                                console.log('Registro eliminado');
                            }
                        }
                    });
                    break;

                default:
                    console.log('Evento no definido');
            }
        }
    },

    onBtnConfirmTap: function(button, e, eOpts) {
        var contMain = Ext.getCmp('contMain');

        var payload = contMain.buildConfigPayload();

        console.info(payload);
        appLocal.saveConfig(payload);
    },

