    buildConfigPayload: function() {
        var form     = Ext.getCmp('formConfig');
        var record   = form.configRecord;
        var isCreate = form.isCreate;

        var id_configuration = record ? record.id_configuration : null;

        const payload = {
            id_configuration : id_configuration,
            cod_configuration: jsTerian.readElementValue("ftCfgCode"),
            name             : jsTerian.readElementValue("ftCfgName"),
            description      : jsTerian.readElementValue("ftCfgDesc"),
            is_active        : jsTerian.readElementValue("cboCfgActive")
        };

        // Validaciones
        if (!payload.cod_configuration || String(payload.cod_configuration).trim() === '') {
            jsTerian.toastAlert("El código es obligatorio.", "error");
            return null;
        }

        if (!payload.name || String(payload.name).trim() === '') {
            jsTerian.toastAlert("El nombre es obligatorio.", "error");
            return null;
        }

        // Normalizar
        payload.cod_configuration = String(payload.cod_configuration).trim().toUpperCase();
        payload.name = String(payload.name).trim();

        if (payload.description !== null && payload.description !== undefined) {
            payload.description = String(payload.description).trim();
        }

        // Create / Update
        if (isCreate) {
            delete payload.id_configuration;
        } else {
            if (!payload.id_configuration) {
                jsTerian.toastAlert("No se puede actualizar: falta id_configuration.", "error");
                return null;
            }

            if (!payload.description || payload.description === '') {
                delete payload.description;
            }
        }

        return payload;
    },

    buildParamPayload: function() {
        var form = Ext.getCmp('formParam');
        var record = form.paramRecord;
        var isCreate = form.isCreate;

        var id_conf_parameter = record ? record.id_conf_parameter : null;

        // OJO: id_configuration normalmente viene “fijo” porque estás editando parámetros dentro de una configuración.
        // Puedes leerlo del form o del record.
        // Si tu form lo tiene guardado: form.id_configuration
        var id_configuration = (record && record.id_configuration) ? record.id_configuration : form.id_configuration;

        const payload = {
          id_conf_parameter: id_conf_parameter,
          id_configuration : id_configuration,
          cod_parameter    : jsTerian.readElementValue("ftParamCode"),
          description      : jsTerian.readElementValue("ftParamDesc"),
          value            : jsTerian.readElementValue("ftParamValue"),
          is_active        : jsTerian.readElementValue("cboParamActive"),
        };

        // Validaciones mínimas
        if (!payload.id_configuration) {
          jsTerian.toastAlert("Falta id_configuration (no se puede guardar el parámetro).", "error");
          return null;
        }

        if (!payload.cod_parameter || String(payload.cod_parameter).trim() === '') {
          jsTerian.toastAlert("El código del parámetro es obligatorio.", "error");
          return null;
        }

        if (!payload.value || String(payload.value).trim() === '') {
          jsTerian.toastAlert("El valor es obligatorio.", "error");
          return null;
        }

        // Normalizar
        payload.cod_parameter = String(payload.cod_parameter).trim().toUpperCase();
        payload.value = String(payload.value).trim();

        if (payload.description !== null && payload.description !== undefined) {
          payload.description = String(payload.description).trim();
        }

        // (Opcional) Si para CFG_APP quieres asegurar que la ruta empiece con "/"
        if (payload.value && payload.value[0] !== '/') {
          payload.value = '/' + payload.value;
        }

        // Create / Update
        if (isCreate) {
          delete payload.id_conf_parameter;

        } else {
          if (!payload.id_conf_parameter) {
            jsTerian.toastAlert("No se puede actualizar: falta id_conf_parameter.", "error");
            return null;
          }

          // si description viene vacía, no la mandes (para no sobreescribir con vacío)
          if (payload.description === '') delete payload.description;
        }

        return payload;
    },

    showConfig: function(record) {
        const mapping = {
          ftCfgCode   : record.cod_configuration,
          ftCfgName   : record.name,
          ftCfgDesc   : record.description,
          cboCfgActive: record.is_active
          // Auditoría?
        };

        Ext.Object.each(mapping, function(field, value){
          jsTerian.assignElementValue(field, value);
        });
    },

    showParam: function(record) {
        // record
        const mapping = {
          ftParamCode   : record.cod_parameter,
          ftParamDesc   : record.description,
          ftParamValue  : record.value,
          cboParamActive: record.is_active
          // Auditoría no por ahora
        };

        Ext.Object.each(mapping, function(field, value){
          jsTerian.assignElementValue(field, value);
        });
    },

